import{_ as t,o as e,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6903_巨漢/20260502/F03_合約負債與營收能見度_財務分析專家.md","filePath":"審計報告庫/財務審計/6903_巨漢/20260502/F03_合約負債與營收能見度_財務分析專家.md"}'),o={name:"審計報告庫/財務審計/6903_巨漢/20260502/F03_合約負債與營收能見度_財務分析專家.md"};function n(l,a,_,s,h,d){return e(),r("div",null,[...a[0]||(a[0]=[i('<h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>合約負債的金額變動趨勢為何？合約負債對營收的領先指標是否顯示未來業績具有高能見度？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>巨漢合約負債從 2024 Q4 9,560 萬暴增至 2025 Q4 6.27 億（+556%），營收能見度從 16.9% 躍升至 38.4%，顯示 2026 年營收具有高度可預測性，屬工程統包業中合約動能強勁的案例。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>A（良偏優）。合約負債連續 4 季增長（3.12 億 → 3.81 億 → 5.11 億 → 6.27 億），訂單動能明確向上，反映半導體廠務需求旺盛。利空：合約負債轉化為營收的速度偏慢（季營收約 6-16 億），需關注工程進度是否落後。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><ol><li><p><strong>合約負債趨勢</strong>：2023 Q4 2.17 億 → 2024 Q4 0.96 億（↓56%，因 2024 年工程量較少且舊合約陸續認列）→ 2025 Q4 6.27 億（↑556%，新增多件大型半導體廠房統包案）。2025 年全年合約負債逐季攀升，無一季衰退，動能穩定。</p></li><li><p><strong>轉化效率分析</strong>：以 2025 Q4 合約負債 6.27 億對比 Q4 營收 16.35 億，能見天數約 35 天（6.27 / (16.35/90)）。若對比季均營收約 10.6 億，能見度約 53 天。對於工程統包業（工程期通常 6-18 個月）來說，53 天能見度偏低，意味著目前合約負債僅代表短期工作量，長期訂單能見度仍需觀察。</p></li><li><p><strong>轉化速度檢驗</strong>：2025 年全年合約負債增加 5.32 億（0.96→6.27），同期營收增加 13.4 億（18.38→31.77）。營收增量 / 合約負債增量 = 2.52 倍，顯示合約負債正高效轉化為營收。若轉化效率維持，2026 年營收有機會挑戰 40-45 億。</p></li></ol><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>能見度不足的風險</strong>：53 天能見度對工程統包業仍偏低。若 2026 年新接案速度放緩，合約負債可能在 2-3 季內快速消耗殆盡，屆時營收動能將斷層。利空：合約負債增量需持續追蹤，否則將出現營收斷崖。</li><li><strong>工程進度延宕壓力</strong>：合約負債大增雖正面，但若工程進度延宕，認列遞延將導致營收不如預期。2025 Q4 單季營收 16.35 億（佔全年 51%）顯示高度集中於年底認列，施工排程風險高，延遲交付將直接侵蝕獲利。</li><li><strong>客戶履約與退款警訊</strong>：合約負債來自半導體客戶的預付款，若客戶資本支出縮減或工程變更，可能導致合約負債回沖（退款），屆時營收預期將同步下修，造成雙重打擊。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>FinMind：TaiwanStockBalanceSheet（CurrentContractLiabilities，2023-2025）</li><li>FinMind：TaiwanStockFinancialStatements（Revenue，2023-2025）</li></ul>',12)])])}const u=t(o,[["render",n]]);export{p as __pageData,u as default};
